import{_ as n,c as a,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Google Cloud: Kredit abfragen | opencode-mystatus","description":"Lernen Sie die Google Cloud-Kreditabfrage-Methode für G3 Pro, G3 Image, G3 Flash und Claude. Zeigen Sie verbleibende Kredite, Rücksetzzeiten an und verwalten Sie mehrere Antigravity-Konten.","frontmatter":{"title":"Google Cloud: Kredit abfragen | opencode-mystatus","sidebarTitle":"Google Cloud-Kredit","subtitle":"Google Cloud-Kreditabfrage: G3 Pro/Image/Flash und Claude","description":"Lernen Sie die Google Cloud-Kreditabfrage-Methode für G3 Pro, G3 Image, G3 Flash und Claude. Zeigen Sie verbleibende Kredite, Rücksetzzeiten an und verwalten Sie mehrere Antigravity-Konten.","tags":["Google Cloud","Antigravity","Kreditabfrage"],"prerequisite":["start-quick-start","start-using-mystatus"],"order":4},"headers":[],"relativePath":"de/vbgate/opencode-mystatus/platforms/google-usage/index.md","filePath":"de/vbgate/opencode-mystatus/platforms/google-usage/index.md"}'),l={name:"de/vbgate/opencode-mystatus/platforms/google-usage/index.md"};function o(r,e,s,d,h,u){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="google-cloud-kreditabfrage-g3-pro-image-flash-und-claude" tabindex="-1">Google Cloud-Kreditabfrage: G3 Pro/Image/Flash und Claude <a class="header-anchor" href="#google-cloud-kreditabfrage-g3-pro-image-flash-und-claude" aria-label="Permalink to &quot;Google Cloud-Kreditabfrage: G3 Pro/Image/Flash und Claude&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><ul><li>Anzeigen der 4 Modellkredite von Google Cloud Antigravity-Konten</li><li>Verstehen der Rücksetzzeit und des verbleibenden Prozentsatzes jedes Modells</li><li>Verwalten der Kreditnutzung mehrerer Google Cloud-Konten</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Google Cloud Antigravity bietet mehrere Modelle (G3 Pro, G3 Image, G3 Flash, Claude), jedes Modell hat einen unabhängigen Kredit und eine Rücksetzzeit. Sie müssen:</p><ul><li>Sich separat in der Google Cloud-Konsole anmelden, um den Status jedes Modells anzuzeigen</li><li>Verbleibende Kredite und Rücksetzzeiten manuell berechnen</li><li>Bei mehreren Konten noch verwirrender sein</li></ul><h2 id="wann-sollten-sie-dies-verwenden" tabindex="-1">Wann sollten Sie dies verwenden? <a class="header-anchor" href="#wann-sollten-sie-dies-verwenden" aria-label="Permalink to &quot;Wann sollten Sie dies verwenden?&quot;">​</a></h2><p>Wenn Sie:</p><ul><li>Schnell die verbleibenden Kredite aller Google Cloud-Modelle erfahren möchten</li><li>Die Nutzungszuteilung zwischen verschiedenen Modellen planen müssen</li><li>Mehrere Google Cloud-Konten haben und einheitlich verwalten möchten</li></ul><h2 id="unterstutzte-modelle" tabindex="-1">Unterstützte Modelle <a class="header-anchor" href="#unterstutzte-modelle" aria-label="Permalink to &quot;Unterstützte Modelle&quot;">​</a></h2><p>mystatus zeigt die Kredite der folgenden 4 Modelle an:</p><table tabindex="0"><thead><tr><th>Anzeigename</th><th>API-Key (Haupt/Reserve)</th><th>Beschreibung</th></tr></thead><tbody><tr><td>G3 Pro</td><td><code>gemini-3-pro-high</code> / <code>gemini-3-pro-low</code></td><td>Gemini 3 Pro Hochleistungs-Version</td></tr><tr><td>G3 Image</td><td><code>gemini-3-pro-image</code></td><td>Gemini 3 Pro-Bildgenerierung</td></tr><tr><td>G3 Flash</td><td><code>gemini-3-flash</code></td><td>Gemini 3 Flash-Schnellversion</td></tr><tr><td>Claude</td><td><code>claude-opus-4-5-thinking</code> / <code>claude-opus-4-5</code></td><td>Claude Opus 4.5-Modell</td></tr></tbody></table><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="schritt-1-abfragebefehl-ausfuhren" tabindex="-1">Schritt 1: Abfragebefehl ausführen <a class="header-anchor" href="#schritt-1-abfragebefehl-ausfuhren" aria-label="Permalink to &quot;Schritt 1: Abfragebefehl ausführen&quot;">​</a></h3><p><strong>Warum</strong> Schnell alle Google Cloud-Kontokredite abrufen</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong> Enthält alle konfigurierten Plattformkredite, der Google Cloud-Abschnitt zeigt ähnlich folgenden Inhalt:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## Google Cloud Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Flash   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>Claude     2d 9h      ░░░░░░░░░░░░░░░░░░░░ 0%</span></span></code></pre></div><h3 id="schritt-2-ausgabeformat-verstehen" tabindex="-1">Schritt 2: Ausgabeformat verstehen <a class="header-anchor" href="#schritt-2-ausgabeformat-verstehen" aria-label="Permalink to &quot;Schritt 2: Ausgabeformat verstehen&quot;">​</a></h3><p><strong>Warum</strong> Schnell Schlüsselinformationen lokalisieren: verbleibender Kredit und Rücksetzzeit</p><p>Jedes Zeilenformat:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Modellname] [Rücksetzzeit] [Fortschrittsbalken] [Verbleibender Prozentsatz]</span></span></code></pre></div><h3 id="schritt-3-mehrere-konten-anzeigen" tabindex="-1">Schritt 3: Mehrere Konten anzeigen <a class="header-anchor" href="#schritt-3-mehrere-konten-anzeigen" aria-label="Permalink to &quot;Schritt 3: Mehrere Konten anzeigen&quot;">​</a></h3><p><strong>Warum</strong> Wenn Sie mehrere Google Cloud-Konten haben, werden sie separat angezeigt</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>### user@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span>G3 Image   4h 59m     ████████████████████ 100%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### another@gmail.com</span></span>
<span class="line"><span></span></span>
<span class="line"><span>G3 Pro     2h 30m     ████████████░░░░░░░░ 75%</span></span>
<span class="line"><span>G3 Image   2h 30m     ██████████░░░░░░░░ 50%</span></span></code></pre></div><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><h3 id="problem-google-cloud-kredit-nicht-sichtbar" tabindex="-1">Problem: Google Cloud-Kredit nicht sichtbar <a class="header-anchor" href="#problem-google-cloud-kredit-nicht-sichtbar" aria-label="Permalink to &quot;Problem: Google Cloud-Kredit nicht sichtbar&quot;">​</a></h3><p><strong>Mögliche Ursachen</strong>:</p><ul><li>opencode-antigravity-auth-Plugin nicht installiert</li><li>Google OAuth-Authentifizierung nicht abgeschlossen</li><li>Datei antigravity-accounts.json nicht vorhanden oder leer</li></ul><p><strong>Lösung</strong>:</p><ol><li>Installieren Sie das opencode-antigravity-auth-Plugin</li><li>Schließen Sie die Authentifizierung gemäß der GitHub-Repository-Dokumentation ab</li><li>Führen Sie <code>/mystatus</code> erneut aus</li></ol><h3 id="problem-konto-zeigt-fehler" tabindex="-1">Problem: Konto zeigt Fehler <a class="header-anchor" href="#problem-konto-zeigt-fehler" aria-label="Permalink to &quot;Problem: Konto zeigt Fehler&quot;">​</a></h3><p><strong>Mögliche Ursachen</strong>:</p><ul><li>Refresh-Token abgelaufen</li><li>projectId fehlt</li></ul><p><strong>Lösung</strong>:</p><ol><li>Authentifizieren Sie das Konto erneut mit dem opencode-antigravity-auth-Plugin</li><li>Stellen Sie sicher, dass die Projekt-ID während der Authentifizierung korrekt festgelegt wurde</li></ol><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><ul><li>Google Cloud Antigravity unterstützt 4 Modelle: G3 Pro, G3 Image, G3 Flash, Claude</li><li>Jedes Modell hat einen unabhängigen Kredit und eine Rücksetzzeit</li><li>Unterstützt Verwaltung mehrerer Konten, jedes Konto zeigt separat 4 Modellkredite</li><li>Wenn die Nutzung 80% überschreitet, wird ein Warnhinweis angezeigt</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../../advanced/google-setup/">Google Cloud-Erweiterte Konfiguration: Mehrere Konten und Modellverwaltung</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie man mehrere Google Cloud-Konten hinzufügt und verwaltet</li><li>Verstehen der Zuordnungsbeziehung der 4 Modelle</li><li>Unterschied zwischen projectId und managedProjectId</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Modellkonfiguration</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L69-L78" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>69-78</td></tr><tr><td>Kontoabfragelogik</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/google.ts#L304-L370" target="_blank" rel="noreferrer"><code>plugin/lib/google.ts</code></a></td><td>304-370</td></tr></tbody></table><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>queryGoogleUsage()</code>: Fragt alle Antigravity-Kontokredite ab</li><li><code>fetchAccountQuota()</code>: Fragt Kredit eines einzelnen Kontos ab</li><li><code>extractModelQuotas()</code>: Extrahiert 4 Modellkredite aus der API-Antwort</li><li><code>formatAccountQuota()</code>: Formatiert die Kreditanzeige eines einzelnen Kontos</li></ul></details>`,43)])])}const p=n(l,[["render",o]]);export{c as __pageData,p as default};
